// SPDX-License-Identifier: ISC
//! Replay of frozen server relay and broadcast decision vectors
//! generated by an in-package dump driving dcrd's real
//! handleRelayPeerInvMsg and handleBroadcastMsg on live piped
//! serverPeers at release-v2.1.5, observing the announced-block
//! field, the recently advertised transaction cache, and the
//! peer-visible inv, headers, and message deliveries — the
//! not-connected and missing-services gates, the block-announcement
//! de-duplication, the inventory-versus-headers preference with its
//! bad-data drop, the transaction relay-disabled and bad-data gates
//! with the advertised-transaction tracking, the mix relay-disabled
//! and protocol-version gates, immediate relay, and the broadcast
//! exclusion — compared row for row.

use dcroxide_chainhash::Hash;
use dcroxide_node::server::{
    RelayInvFacts, RelayPeerAction, RelayPeerFacts, handle_relay_peer_inv, should_broadcast_to_peer,
};
use dcroxide_wire::{InvType, MIX_VERSION, PROTOCOL_VERSION, ServiceFlag};

const VECTORS: &str = include_str!("data/srvrelay2_vectors.txt");

fn hash_of(b: u8) -> Hash {
    let mut h = [0u8; 32];
    h[0] = b;
    Hash(h)
}

/// The base facts for a connected, full-relay peer at the default
/// protocol version.
fn base_peer() -> RelayPeerFacts {
    RelayPeerFacts {
        connected: true,
        services: ServiceFlag::NODE_NETWORK,
        wants_headers: false,
        disable_relay_tx: false,
        protocol_version: PROTOCOL_VERSION,
    }
}

fn queued(action: RelayPeerAction) -> bool {
    matches!(
        action,
        RelayPeerAction::QueueInventory | RelayPeerAction::QueueInventoryImmediate
    )
}

/// Look up a row by its second field.
fn row<'a>(name: &str) -> Vec<&'a str> {
    VECTORS
        .lines()
        .map(|l| l.split('|').collect::<Vec<&str>>())
        .find(|f| f[1] == name)
        .unwrap_or_else(|| panic!("missing row {name}"))
}

#[test]
fn server_relay_broadcast_matches_dcrd() {
    // not connected: the announced block is left untouched and
    // nothing is relayed.
    let f = row("notconnected");
    let mut announced = Some(hash_of(9));
    let out = handle_relay_peer_inv(
        &mut announced,
        &RelayPeerFacts {
            connected: false,
            ..base_peer()
        },
        &RelayInvFacts {
            inv_type: InvType::BLOCK,
            inv_hash: hash_of(1),
            req_services: ServiceFlag(0),
            immediate: false,
            data_is_block_header: true,
            data_is_tx: false,
        },
    );
    assert_eq!(out.action, RelayPeerAction::Ignore);
    assert_eq!((announced == Some(hash_of(9))).to_string(), f[2]);
    // The peer is disconnected in the dump; the port never queues.
    assert_eq!(f[3], "false");

    // missing required services.
    let f = row("missingservices");
    let mut announced = None;
    let out = handle_relay_peer_inv(
        &mut announced,
        &base_peer(),
        &RelayInvFacts {
            inv_type: InvType::BLOCK,
            inv_hash: hash_of(1),
            // The dump requires SFNodeNetwork << 1, which the peer
            // lacks.
            req_services: ServiceFlag(ServiceFlag::NODE_NETWORK.0 << 1),
            immediate: false,
            data_is_block_header: true,
            data_is_tx: false,
        },
    );
    assert_eq!(queued(out.action).to_string(), f[2]);
    assert_eq!((announced.is_some()).to_string(), f[3]);

    // block announcement de-duplication clears the announced block.
    let f = row("blockdedup");
    let mut announced = Some(hash_of(2));
    let out = handle_relay_peer_inv(&mut announced, &base_peer(), &block_inv(2));
    assert_eq!(queued(out.action).to_string(), f[2]);
    assert_eq!((announced.is_none()).to_string(), f[3]);

    // block announcement, no headers preference: inventory relayed
    // and the announced block recorded.
    let f = row("blockinv");
    let mut announced = None;
    let out = handle_relay_peer_inv(&mut announced, &base_peer(), &block_inv(3));
    assert_eq!(queued(out.action).to_string(), f[2]);
    assert_eq!((announced == Some(hash_of(3))).to_string(), f[3]);

    // block announcement, headers preference: headers queued.
    let f = row("blockheaders");
    let mut announced = None;
    let out = handle_relay_peer_inv(
        &mut announced,
        &RelayPeerFacts {
            wants_headers: true,
            ..base_peer()
        },
        &block_inv(4),
    );
    assert_eq!(
        (out.action == RelayPeerAction::QueueHeaders).to_string(),
        f[2]
    );
    // The peer wants headers.
    assert_eq!(f[3], "true");

    // block announcement, headers preference, bad data: nothing.
    let f = row("blockheadersbaddata");
    let mut announced = None;
    let out = handle_relay_peer_inv(
        &mut announced,
        &RelayPeerFacts {
            wants_headers: true,
            ..base_peer()
        },
        &RelayInvFacts {
            data_is_block_header: false,
            ..block_inv(5)
        },
    );
    assert_eq!(
        (out.action == RelayPeerAction::QueueHeaders).to_string(),
        f[2]
    );
    assert_eq!(queued(out.action).to_string(), f[3]);

    // transaction relay tracks the advertised transaction.
    let f = row("txrelay");
    let mut announced = None;
    let out = handle_relay_peer_inv(&mut announced, &base_peer(), &tx_inv(6, true));
    assert_eq!(queued(out.action).to_string(), f[2]);
    assert_eq!((out.advertised_tx == Some(hash_of(6))).to_string(), f[3]);

    // transaction relay disabled.
    let f = row("txdisabled");
    let mut announced = None;
    let out = handle_relay_peer_inv(
        &mut announced,
        &RelayPeerFacts {
            disable_relay_tx: true,
            ..base_peer()
        },
        &tx_inv(7, true),
    );
    assert_eq!(queued(out.action).to_string(), f[2]);
    assert_eq!((out.advertised_tx.is_some()).to_string(), f[3]);

    // transaction relay with bad data.
    let f = row("txbaddata");
    let mut announced = None;
    let out = handle_relay_peer_inv(&mut announced, &base_peer(), &tx_inv(8, false));
    assert_eq!(queued(out.action).to_string(), f[2]);
    assert_eq!((out.advertised_tx.is_some()).to_string(), f[3]);

    // mix relay.
    let f = row("mixrelay");
    let mut announced = None;
    let out = handle_relay_peer_inv(&mut announced, &base_peer(), &mix_inv(10));
    assert_eq!(queued(out.action).to_string(), f[2]);

    // mix relay disabled.
    let f = row("mixdisabled");
    let mut announced = None;
    let out = handle_relay_peer_inv(
        &mut announced,
        &RelayPeerFacts {
            disable_relay_tx: true,
            ..base_peer()
        },
        &mix_inv(11),
    );
    assert_eq!(queued(out.action).to_string(), f[2]);

    // mix relay unsupported by the negotiated protocol version.
    let f = row("mixunsupported");
    let mut announced = None;
    let out = handle_relay_peer_inv(
        &mut announced,
        &RelayPeerFacts {
            protocol_version: MIX_VERSION - 1,
            ..base_peer()
        },
        &mix_inv(12),
    );
    assert_eq!(queued(out.action).to_string(), f[2]);
    assert_eq!((MIX_VERSION - 1).to_string(), f[3]);

    // immediate relay.
    let f = row("immediate");
    let mut announced = None;
    let out = handle_relay_peer_inv(
        &mut announced,
        &base_peer(),
        &RelayInvFacts {
            immediate: true,
            ..tx_inv(13, true)
        },
    );
    assert_eq!(
        (out.action == RelayPeerAction::QueueInventoryImmediate).to_string(),
        f[2]
    );

    // broadcast to a connected non-excluded peer.
    let f = row("delivered");
    assert_eq!(should_broadcast_to_peer(true, false).to_string(), f[2]);

    // broadcast excluding the peer.
    let f = row("excluded");
    assert_eq!(should_broadcast_to_peer(true, true).to_string(), f[2]);
}

fn block_inv(b: u8) -> RelayInvFacts {
    RelayInvFacts {
        inv_type: InvType::BLOCK,
        inv_hash: hash_of(b),
        req_services: ServiceFlag(0),
        immediate: false,
        data_is_block_header: true,
        data_is_tx: false,
    }
}

fn tx_inv(b: u8, valid: bool) -> RelayInvFacts {
    RelayInvFacts {
        inv_type: InvType::TX,
        inv_hash: hash_of(b),
        req_services: ServiceFlag(0),
        immediate: false,
        data_is_block_header: false,
        data_is_tx: valid,
    }
}

fn mix_inv(b: u8) -> RelayInvFacts {
    RelayInvFacts {
        inv_type: InvType::MIX,
        inv_hash: hash_of(b),
        req_services: ServiceFlag(0),
        immediate: false,
        data_is_block_header: false,
        data_is_tx: false,
    }
}
